+        "create_epic",
+    );
+
+    assert!(
+        br_create.status.success(),
+        "br create epic failed: {}",
+        br_create.stderr
+    );
+    assert!(
+        bd_create.status.success(),
+        "bd create epic failed: {}",
+        bd_create.stderr
+    );
+
+    // Get epic status
+    let br_out = workspace.run_br(["epic", "status", "--json"], "epic_status");
