+    for i in 1..count {
+        let label = format!("dep_{}", i);
+
+        let br_out = workspace.run_br(["dep", "add", &br_ids[i], &br_ids[i - 1]], &label);
+        let bd_out = workspace.run_bd(["dep", "add", &bd_ids[i], &bd_ids[i - 1]], &label);
+
