+        create_issue(&workspace, &format!("Issue {i}"), &format!("create_{i}"));
+        sync_flush(&workspace);
+    }
+
+    // List backups
+    let list = run_br(&workspace, ["history", "list"], "history_list_multiple");
+    assert!(list.status.success());
+
