+    );
+
+    // Backups should be sorted by timestamp (list_backup_files sorts them)
+    let sorted_backups = {
+        let mut b = backups.clone();
+        b.sort();
+        b
+    };
+    assert_eq!(backups, sorted_backups, "backups should be sorted");
+}
